body.script:
test(function() {
  assert_not_background_color('t1', LIME);
  assert_not_background_color('t1', RED);
  assert_background_color('t2', LIME);
  assert_not_background_color('t3', LIME);
  assert_not_background_color('t3', RED);
  assert_background_color('t4', LIME);
}, 'NEGATED Attribute space-separated value selector without declared namespace');
